        [Fact]
        public void WFiltro_DtCad_WhenValidSingleDate_ShouldAddParameterAndGenerateWhereClause()
        {
            // Arrange
            var testDate = "15/06/2023";
            var filtro = new FilterTribunal
            {
                DtCad = testDate,
                DtCad_end = string.Empty,
                LogicalOperator = TSql.And
            };
            // Act
